// In-memory fallback storage (resets on each deployment)
const memoryStore: Map<string, string> = new Map();

function getStore(env: any, bindingName: string): { get: (key: string) => Promise<string | null>; put: (key: string, value: string, opts?: any) => Promise<void>; delete?: (key: string) => Promise<void> } {
  if (env[bindingName]) {
    return env[bindingName];
  }
  return {
    get: async (key: string) => memoryStore.get(key) || null,
    put: async (key: string, value: string, opts?: any) => { memoryStore.set(key, value); },
    delete: async (key: string) => { memoryStore.delete(key); },
  };
}

