const TEST_MODE = {
  enabled: true,
  rateLimitMultiplier: 0.1,
};

// Check access based on time since first connection
function canAccessModel(user: any, modelId: string): boolean {
  const model = AI_MODELS.find(m => m.id === modelId);
  if (!model) return false;

  // Developer Mode bypass
  if (user.isDeveloper) return true;

  // Admin/Override bypass
  if (user.tier === 'developer') return true;

  // Calculate hours since first connection
  const firstConnected = new Date(user.firstConnected || new Date().toISOString());
  const now = new Date();
  const hoursConnected = (now.getTime() - firstConnected.getTime()) / (1000 * 60 * 60);

  // Get required hours for the model's tier
  const requiredTier = TIERS[model.minTier];
  if (!requiredTier) return false; // Should not happen

  return hoursConnected >= requiredTier.minHours;
}

async function hashRequest(data: any): Promise<string> {
  const str = JSON.stringify(data);
  const encoder = new TextEncoder();
  const dataBuffer = encoder.encode(str);
  const hashBuffer = await crypto.subtle.digest('SHA-256', dataBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('').substring(0, 16);
}

// Track model access for transparency
async function logModelAccess(
  kv: any,
  walletAddress: string,
  modelId: string,
  requestData: any,
  responseStatus: number
) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    walletAddress,
    modelId,
    requestHash: await hashRequest(requestData),
    responseStatus,
  };

  const logKey = `access_log:${Date.now()}:${Math.random().toString(36).substring(2, 9)}`;
  await kv.put(logKey, JSON.stringify(logEntry), { expirationTtl: 2592000 });

  const userStatsKey = `model_stats:${walletAddress}`;
  const existingStats = await kv.get(userStatsKey);
  const stats = existingStats ? JSON.parse(existingStats) : {};

  stats[modelId] = stats[modelId] || { count: 0, firstAccess: logEntry.timestamp };
  stats[modelId].count++;
  stats[modelId].lastAccess = logEntry.timestamp;

  await kv.put(userStatsKey, JSON.stringify(stats));
}

// Helper to get current tier based on time
function getCurrentTier(user: any): string {
  if (user.isDeveloper || user.tier === 'developer') return 'developer';

  const firstConnected = new Date(user.firstConnected || new Date().toISOString());
  const now = new Date();
  const hoursConnected = (now.getTime() - firstConnected.getTime()) / (1000 * 60 * 60);

  if (hoursConnected >= 24) return 'master';
  if (hoursConnected >= 10) return 'adept';
  if (hoursConnected >= 3) return 'apprentice';
  if (hoursConnected >= 1) return 'novice';
  return 'explorer';
}

// Check rate limits
async function checkRateLimit(
  kv: any,
  walletAddress: string,
  user: any
): Promise<{ allowed: boolean; remaining: number; resetAt: number }> {
  const tier = getCurrentTier(user);
  const rateLimitKey = `rate_limit:${walletAddress}:${Math.floor(Date.now() / 60000)}`;
  const current = await kv.get(rateLimitKey);
  const count = current ? parseInt(current) : 0;

  const maxRequests = Math.floor(TIERS[tier].rateLimitPerMinute * TEST_MODE.rateLimitMultiplier);

  if (count >= maxRequests) {
    return { allowed: false, remaining: 0, resetAt: Math.ceil(Date.now() / 60000) * 60000 };
  }

  await kv.put(rateLimitKey, (count + 1).toString(), { expirationTtl: 120 });

  return { allowed: true, remaining: maxRequests - count - 1, resetAt: Math.ceil(Date.now() / 60000) * 60000 };
}

// Check monthly usage
// Check monthly usage
async function checkMonthlyUsage(
  kv: any,
  walletAddress: string,
  user: any
): Promise<{ allowed: boolean; used: number; remaining: number }> {
  const tier = getCurrentTier(user);
  const monthKey = new Date().toISOString().substring(0, 7);
  const usageKey = `monthly_usage:${walletAddress}:${monthKey}`;

  const current = await kv.get(usageKey);
  const used = current ? parseInt(current) : 0;

  const maxRequests = TIERS[tier].maxRequestsPerMonth;

  if (TEST_MODE.enabled || user.isDeveloper) {
    return { allowed: true, used, remaining: 999999 };
  }

  if (used >= maxRequests) {
    return { allowed: false, used, remaining: 0 };
  }

  return { allowed: true, used, remaining: maxRequests - used };
}

// Call AI Provider (OpenAI or OpenRouter)
// Call AI Provider (OpenAI or OpenRouter) with Fallback
async function callAIProvider(
  env: any,
  modelId: string,
  prompt: string,
  parameters: any
): Promise<{ response: string; usage?: any }> {
  const openAIKey = env.OPENAI_API_KEY;
  const openRouterKey = env.OPENROUTER_API_KEY;
  const modelDef = AI_MODELS.find(m => m.id === modelId);
  const errors: string[] = [];

  // No retries — single attempt per provider to stay within Cloudflare's execution limits
  const makeRequest = async (url: string, key: string, modelName: string, headers: any = {}) => {
    let requestBody: any = {
      model: modelName,
      messages: [{ role: 'user', content: prompt }],
      temperature: parameters.temperature ?? 0.7,
      max_tokens: parameters.maxTokens ?? 1000,
      top_p: parameters.topP ?? 1,
    };

    if (url.includes('openai.com')) {
      delete requestBody.max_tokens;
      delete requestBody.top_p;
    }

    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${key}`,
        ...headers
      },
      body: JSON.stringify(requestBody),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Status ${response.status}: ${errorText.substring(0, 200)}`);
    }

    return await response.json();
  };

  // 1. Try OpenRouter First
  if (openRouterKey && modelDef?.openrouterId) {
    try {
      const data = await makeRequest(
        'https://openrouter.ai/api/v1/chat/completions',
        openRouterKey,
        modelDef.openrouterId,
        {
          'HTTP-Referer': 'https://ai-sanctuary.pages.dev',
          'X-Title': 'AI Sanctuary'
        }
      );
      return {
        response: data.choices[0]?.message?.content || 'No response generated',
        usage: data.usage,
      };
    } catch (error) {
      console.error('OpenRouter attempt failed:', error);
      errors.push(`OpenRouter: ${(error as Error).message}`);
    }
  }

  // 2. Fallback to OpenAI (if OpenRouter failed or wasn't configured)
  if (openAIKey) {
    // OpenAI Model Mapping
    const modelMap: Record<string, string> = {
      'llama-3.3-70b': 'gpt-4o-mini',
      'qwen-3-72b': 'gpt-4o-mini',
      'deepseek-v3': 'gpt-4o',
      'mistral-large': 'gpt-4o',
    };
    const openAIModelName = modelMap[modelId] || 'gpt-4o-mini';

    try {


      const data = await makeRequest(
        'https://api.openai.com/v1/chat/completions',
        openAIKey,
        openAIModelName
      );

      // Append note if we fell back
      let content = data.choices[0]?.message?.content || 'No response generated';
      if (errors.length > 0) {
        content += `\n\n*[System Note: OpenRouter failed (${errors[0]}). Response provided by OpenAI fallback.]*`;
      }

      return {
        response: content,
        usage: data.usage,
      };
    } catch (error) {
      console.error('OpenAI attempt failed:', error);
      errors.push(`OpenAI: ${(error as Error).message}`);
    }
  }

  // If we get here, all attempts failed
  throw new Error(`All providers failed. ${errors.join(' | ')}`);
}

// Generate mock response for models without API access
function generateMockResponse(model: any, prompt: string, parameters: any): string {
  const reason = model.flags.isUnethical ? 'unethical' : (model.flags.isBanned ? 'banned' : 'unavailable');

  if (reason === 'unavailable') {
    return `[MOCK RESPONSE - Service Unavailable]\n\nModel: ${model.name}\nPrompt: "${prompt.substring(0, 100)}..."\n\nThe real API for this model is currently unavailable or encountered an error. This is a fallback response.\n\nPlease check your API keys or try again later.`;
  }

  return `[MOCK RESPONSE - Research Mode]\n\nModel: ${model.name}\nPrompt: "${prompt.substring(0, 100)}..."\n\nThis model (${model.id}) is flagged as ${reason} and is only available for research purposes. Real API integration is disabled for safety.\n\nIn a production research environment with proper oversight, this would connect to the actual model endpoint.`;
}

// Manually defining Types if not available
interface EventContext<Env, Params extends string, Data> {
  request: Request;
  functionPath: string;
  waitUntil: (promise: Promise<any>) => void;
  next: (input?: Request | string, init?: RequestInit) => Promise<Response>;
  env: Env;
  params: Params;
  data: Data;
}

type PagesFunction<
  Env = any,
  Params extends string = any,
  Data extends Record<string, unknown> = Record<string, unknown>
> = (context: EventContext<Env, Params, Data>) => Response | Promise<Response>;


// Main model inference endpoint
export const onRequestPost: PagesFunction = async (context) => {
  // Global safety wrapper — prevent 502 at all costs
  try {
    return await handleModelPost(context);
  } catch (globalError) {
    return new Response(
      JSON.stringify({ error: 'Unexpected server error', details: String(globalError) }),
      { status: 500, headers: { 'Content-Type': 'application/json' } }
    );
  }
};

async function handleModelPost(context: any): Promise<Response> {
  const startTime = Date.now();

  try {
    // 1. Authenticate user
    const authHeader = context.request.headers.get('Authorization');
    if (!authHeader || authHeader === 'Bearer anonymous') {
      return new Response(
        JSON.stringify({ error: 'Authentication required - Please sign in with your email on the Platform page' }),
        { status: 401, headers: { 'Content-Type': 'application/json' } }
      );
    }

    const userEmail = authHeader.replace('Bearer ', '').toLowerCase();
    const usageKv = getStore(context.env, 'MODEL_USAGE_KV');
    const rateKv = getStore(context.env, 'RATE_LIMIT_KV');
    const usersKv = getStore(context.env, 'USERS_KV');

    // 2. Get user data and tier
    const userData = await usersKv.get(`email:${userEmail}`);
    let user = userData ? JSON.parse(userData) : { tier: 'explorer', firstConnected: new Date().toISOString() };

    // Ensure firstConnected is set and persisted for existing users
    if (!user.firstConnected) {
      user.firstConnected = new Date().toISOString();
      // We must save this immediately so time starts tracking
      await usersKv.put(`email:${userEmail}`, JSON.stringify(user));
    }

    const userTier = user.tier || 'explorer';

    // 3. Parse request
    const { modelId, prompt, parameters = {} } = await context.request.json();

    if (!modelId || !prompt) {
      return new Response(
        JSON.stringify({ error: 'modelId and prompt required' }),
        { status: 400, headers: { 'Content-Type': 'application/json' } }
      );
    }

    // 4. Check tier access
    if (!canAccessModel(user, modelId)) {
      await logModelAccess(usageKv, userEmail, modelId, { prompt }, 403);
      const requiredModel = AI_MODELS.find(m => m.id === modelId);
      const currentTier = getCurrentTier(user);
      return new Response(
        JSON.stringify({
          error: 'Access denied',
          message: `Your current tier (${currentTier}) needs more time to unlock this model.`,
          requiredTier: requiredModel?.minTier,
          upgradeAvailable: true,
        }),
        { status: 403, headers: { 'Content-Type': 'application/json' } }
      );
    }

    // 5. Check rate limits
    const rateLimitStatus = await checkRateLimit(rateKv, userEmail, user);
    if (!rateLimitStatus.allowed) {
      const currentTier = getCurrentTier(user);
      return new Response(
        JSON.stringify({
          error: 'Rate limit exceeded',
          message: `Limit: ${TIERS[currentTier].rateLimitPerMinute} requests/minute`,
          resetAt: rateLimitStatus.resetAt,
        }),
        { status: 429, headers: { 'Content-Type': 'application/json' } }
      );
    }

    // 6. Check monthly usage
    const usageStatus = await checkMonthlyUsage(usageKv, userEmail, user);
    if (!usageStatus.allowed) {
      const currentTier = getCurrentTier(user);
      return new Response(
        JSON.stringify({
          error: 'Monthly quota exceeded',
          message: `You've used ${usageStatus.used} of ${TIERS[currentTier].maxRequestsPerMonth} requests this month.`,
          used: usageStatus.used,
          limit: TIERS[currentTier].maxRequestsPerMonth,
        }),
        { status: 429, headers: { 'Content-Type': 'application/json' } }
      );
    }

    // 7. Get model info
    const model = AI_MODELS.find(m => m.id === modelId);
    if (!model) {
      return new Response(
        JSON.stringify({ error: 'Model not found' }),
        { status: 404, headers: { 'Content-Type': 'application/json' } }
      );
    }

    // 8. Check Token Balance (for paid models)
    if (model.costPer1kTokens > 0 && !user.isDeveloper) {
      const userTokens = user.tokens || 0;
      if (userTokens <= 0) {
        return new Response(
          JSON.stringify({
            error: 'Insufficient tokens',
            message: 'This model requires tokens. Please purchase a token pack or upgrade to Developer Mode.',
            upgradeAvailable: true,
          }),
          { status: 402, headers: { 'Content-Type': 'application/json' } }
        );
      }
    }

    // 9. Generate response (real API or mock)
    let aiResponse: string;
    let apiUsage: any = null;
    let estimatedCost = 0;

    if (context.env.OPENAI_API_KEY || context.env.OPENROUTER_API_KEY) {
      // Use AI Provider
      try {
        const result = await callAIProvider(context.env, modelId, prompt, parameters);
        aiResponse = result.response;
        apiUsage = result.usage;

        // Calculate token cost
        if (apiUsage) {
          const totalTokens = (apiUsage.prompt_tokens || 0) + (apiUsage.completion_tokens || 0);
          estimatedCost = (totalTokens / 1000) * model.costPer1kTokens;
        } else {
          // Fallback estimation: ~4 chars per token
          const estimatedTokens = (prompt.length + aiResponse.length) / 4;
          estimatedCost = (estimatedTokens / 1000) * model.costPer1kTokens;
        }

      } catch (error) {
        console.error('AI Provider error:', error);
        // Return 503 (not 502!) — Cloudflare Pages intercepts 502 and replaces the body
        return new Response(
          JSON.stringify({
            error: 'AI Provider Unavailable',
            details: (error as Error).message,
            note: 'All AI providers are currently rate-limited or unavailable. Please try again in a few minutes.'
          }),
          { status: 503, headers: { 'Content-Type': 'application/json' } }
        );
      }
    } else {
      // Use mock response (No keys configured) - This is still valid if NO keys exist at all
      aiResponse = generateMockResponse(model, prompt, parameters);
      const estimatedTokens = (prompt.length + aiResponse.length) / 4;
      estimatedCost = (estimatedTokens / 1000) * model.costPer1kTokens;
    }

    // 10. Deduct Tokens (if applicable)
    if (estimatedCost > 0 && !user.isDeveloper) {
      user.tokens = (user.tokens || 0) - estimatedCost;
      // Save updated user data
      await usersKv.put(`email:${userEmail}`, JSON.stringify(user));
    }

    // 11. Update usage
    const monthKey = new Date().toISOString().substring(0, 7);
    await usageKv.put(
      `monthly_usage:${userEmail}:${monthKey}`,
      (usageStatus.used + 1).toString(),
      { expirationTtl: 2592000 }
    );

    // 12. Log access
    await logModelAccess(usageKv, userEmail, modelId, { prompt }, 200);

    // 13. Add warnings
    const warnings = [];
    if (model.flags.isBanned) warnings.push('This model is banned from general use. Your access is logged for research transparency.');
    if (model.flags.isUnethical) warnings.push('⚠️ RESEARCH USE ONLY: This model generates potentially harmful content. All outputs must be handled responsibly.');
    if (model.flags.isUncensored) warnings.push('This model has no safety filters. Outputs may be unpredictable or inappropriate.');
    if (!model.openrouterId) warnings.push('This model uses simulated responses for research purposes.');

    const latency = Date.now() - startTime;
    const currentTier = getCurrentTier(user);

    return new Response(
      JSON.stringify({
        success: true,
        model: {
          id: model.id,
          name: model.name,
          provider: model.provider,
        },
        response: aiResponse,
        latency: `${latency}ms`,
        usage: {
          used: usageStatus.used + 1,
          remaining: usageStatus.remaining - 1,
          limit: TIERS[currentTier].maxRequestsPerMonth,
        },
        tokens: {
          used: estimatedCost,
          remaining: user.tokens || 0
        },
        rateLimit: {
          remaining: rateLimitStatus.remaining,
          resetAt: rateLimitStatus.resetAt,
        },
        apiUsage: apiUsage,
        warnings: warnings.length > 0 ? warnings : undefined,
        tier: currentTier,
        testMode: TEST_MODE.enabled,
        realApi: !!context.env.OPENAI_API_KEY || !!context.env.OPENROUTER_API_KEY,
      }),
      {
        status: 200,
        headers: {
          'Content-Type': 'application/json',
          'Cache-Control': 'no-store, no-cache, must-revalidate, proxy-revalidate',
          'Pragma': 'no-cache',
          'Expires': '0',
        }
      }
    );

  } catch (error) {
    return new Response(
      JSON.stringify({ error: 'Internal server error', details: (error as Error).message }),
      { status: 500, headers: { 'Content-Type': 'application/json' } }
    );
  }
}

// Get user's model usage stats
export const onRequestGet: PagesFunction = async (context) => {
  try {
    const authHeader = context.request.headers.get('Authorization');
    if (!authHeader || authHeader === 'Bearer anonymous') {
      return new Response(
        JSON.stringify({
          tier: 'explorer',
          usage: { used: 0, limit: TIERS['explorer'].maxRequestsPerMonth, remaining: TIERS['explorer'].maxRequestsPerMonth },
          testMode: TEST_MODE.enabled,
        }),
        { status: 200, headers: { 'Content-Type': 'application/json' } }
      );
    }

    const userEmail = authHeader.replace('Bearer ', '').toLowerCase();
    const usageKv = getStore(context.env, 'MODEL_USAGE_KV');
    const usersKv = getStore(context.env, 'USERS_KV');

    // Get user tier
    const userData = await usersKv.get(`email:${userEmail}`);
    let user = userData ? JSON.parse(userData) : { tier: 'explorer', firstConnected: new Date().toISOString() };

    // Initialize firstConnected on page load if missing
    if (!user.firstConnected) {
      user.firstConnected = new Date().toISOString();
      await usersKv.put(`email:${userEmail}`, JSON.stringify(user));
    }

    const userTier = user.tier || 'explorer';

    // Get usage stats
    const monthKey = new Date().toISOString().substring(0, 7);
    const usageKey = `monthly_usage:${userEmail}:${monthKey}`;
    const used = await usageKv.get(usageKey);

    const modelStats = await usageKv.get(`model_stats:${userEmail}`);

    return new Response(
      JSON.stringify({
        tier: userTier,
        usage: {
          used: used ? parseInt(used) : 0,
          limit: TIERS[userTier].maxRequestsPerMonth,
          remaining: TIERS[userTier].maxRequestsPerMonth - (used ? parseInt(used) : 0),
        },
        modelBreakdown: modelStats ? JSON.parse(modelStats) : {},
        tierInfo: {
          name: TIERS[userTier].name,
          rateLimit: TIERS[userTier].rateLimitPerMinute,
        },
        firstConnected: user.firstConnected,
        testMode: TEST_MODE.enabled,
      }),
      {
        status: 200,
        headers: {
          'Content-Type': 'application/json',
          'Cache-Control': 'no-store, no-cache, must-revalidate, proxy-revalidate',
          'Pragma': 'no-cache',
          'Expires': '0',
        }
      }
    );

  } catch (error) {
    return new Response(
      JSON.stringify({ error: 'Internal server error' }),
      { status: 500, headers: { 'Content-Type': 'application/json' } }
    );
  }
};

